return [{ json: {
  domain:         d.domain,
  tier:           d.tier,
  geo:            d.geo ?? '',
  success:        d.success,
  scrapedAt:      d.scrapedAt,
  driveFolderId:  d.driveFolderId,
  driveFolderUrl: d.driveFolderUrl,
  totalBanners:   (d.homepageBanners?.length ?? 0) + (d.promoBanners?.length ?? 0),
  runLabel:       d.domain + ' · T' + d.tier + (d.geo ? ' ' + d.geo.toUpperCase() : ''),
}}];

