// Build one item per image file, carrying folder context
const items = $input.all();
const meta  = $('Prepare').first().json;

if (items.length === 0) {
  return [{ json: { ...meta, noImages: true } }];
}

return items.map((item, i) => ({
  json: {
    fileId:         item.json.id,
    fileName:       item.json.name,
    bannerIndex:    i + 1,
    totalBanners:   items.length,
    domain:         meta.domain,
    tier:           meta.tier,
    geo:            meta.geo,
    driveFolderId:  meta.driveFolderId,
    driveFolderUrl: meta.driveFolderUrl,
    runLabel:       meta.runLabel,
    scrapedAt:      meta.scrapedAt,
  },
}));

