// Convert binary image to base64 for Claude Vision API
const item = $input.first();
const imageBuffer = item.binary?.imageData?.data;
if (!imageBuffer) throw new Error('No binary data found on imageData property');

const base64 = Buffer.isBuffer(imageBuffer)
  ? imageBuffer.toString('base64')
  : imageBuffer;  // already base64 string in some n8n versions

const mimeType = item.binary?.imageData?.mimeType ?? 'image/jpeg';

return [{ json: {
  ...item.json,
  base64Image: base64,
  mimeType,
}}];

