// Extract the text from Claude's response
const item = $input.first();
const claudeResponse = item.json;
const prompt = claudeResponse?.content?.[0]?.text ?? '(no prompt generated)';

return [{ json: {
  ...item.json,
  generatedPrompt: prompt,
  fileName: item.json.fileName,
  bannerIndex: item.json.bannerIndex,
  domain: item.json.domain,
  driveFolderId: item.json.driveFolderId,
  driveFolderUrl: item.json.driveFolderUrl,
  runLabel: item.json.runLabel,
  scrapedAt: item.json.scrapedAt,
  totalBanners: item.json.totalBanners,
}}];

// Format all generated prompts as a readable markdown file
const allItems = $input.first().json.data;
if (!allItems || allItems.length === 0) return [{ json: { markdown: '# No prompts generated', folderId: '', folderUrl: '', domain: '', runLabel: '' } }];

const first = allItems[0];
const date  = new Date(first.scrapedAt || Date.now()).toISOString().slice(0, 10);

const lines = [
  `# ${first.domain} — Banner Prompts`,
  `**Scraped:** ${date}  |  **Tier:** ${first.tier}${first.geo ? '  |  **Geo:** ' + first.geo.toUpperCase() : ''}`,
  `**Banners analysed:** ${allItems.length}`,
  ``,
  `---`,
  ``,
];

allItems.forEach((item, i) => {
  lines.push(`## Banner ${i + 1}  \`${item.fileName}\``);
  lines.push(``);
  lines.push(item.generatedPrompt ?? '*(no prompt)*');
  lines.push(``);
  lines.push(`---`);
  lines.push(``);
});

return [{ json: {
  markdown:       lines.join('\n'),
  folderId:       first.driveFolderId,
  folderUrl:      first.driveFolderUrl,
  domain:         first.domain,
  runLabel:       first.runLabel,
  promptCount:    allItems.length,
}}];

// Convert markdown string to binary so Google Drive can upload it
const item = $input.first();
const markdown = item.json.markdown ?? '';
const buffer   = Buffer.from(markdown, 'utf-8');

return [{
  json: item.json,
  binary: {
    data: {
      data:     buffer.toString('base64'),
      mimeType: 'text/markdown',
      fileName: 'prompts.md',
    },
  },
}];
